package data;
import com.fasterxml.jackson.core.type.TypeReference;import models.LoginUser;import org.testng.annotations.DataProvider;import utils.ExcelUtil;import utils.JsonUtil;import java.util.*;
public class LoginDataProvider { @DataProvider(name="validLoginJson", parallel=true) public Object[][] validLoginJson(){ List<LoginUser> users=JsonUtil.readList("testdata/login-users.json", new TypeReference<>(){}); return users.stream().map(u -> new Object[]{u}).toArray(Object[][]::new); } @DataProvider(name="validLoginExcel", parallel=true) public Object[][] validLoginExcel(){ Object[][] rows=ExcelUtil.readSheet("testdata/login.xlsx","login"); return Arrays.stream(rows).map(r -> { Map<String,String> m=(Map<String,String>)r[0]; return new Object[]{new LoginUser(m.get("username"),m.get("password"),m.get("expectedHeading"))}; }).toArray(Object[][]::new); } }
